import { useState, createContext, useEffect } from 'react';
import supabaseClient from '../supabase.js'
import { useNavigate } from 'react-router-dom'

const AuthContext = createContext();


const AuthProvider = ({children}) => {
    

    const [user, setUser] = useState({
        email: '',
        password: ''
    });
    const [session, setSession] = useState(null);
    const [loading, setLoading] = useState(true);
    const [ errorMessage, setErrorMessage ] = useState('')

    const navigate = useNavigate()
  

    const dataUser = e => {
        setUser({
            ...user,
            [e.target.name]: e.target.value
        })
    }
    
    async function logIn(e) {
        e.preventDefault()
        setErrorMessage('')
        
        try {
          const { data, error } = await supabaseClient.auth.signInWithPassword(user)

          if(data)
          {
            navigate('/register')
          }

          switch(error.message)
          {
            case 'Invalid login credentials':
              setErrorMessage("Credenciales invalidas")
            break;

            default:
              setErrorMessage("Error")
            break;
          }
        } catch(error)
        {
          setErrorMessage("Error inesperado. Volvé a intentarlo en unos minutos.")
        }
        
        
    }

    const logOut = () => supabaseClient.auth.signOut()


    useEffect(() => {
      supabaseClient.auth.getSession().then(({ data: { session } }) => {
        setSession(session)
        setLoading(false)
      })

      const {
        data: { subscription },
      } = supabaseClient.auth.onAuthStateChange((_event, session) => {
        setSession(session)
      })

      return () => subscription.unsubscribe()
    }, [])
   

    return (
        <AuthContext.Provider value={{ user, session, logOut, setUser, dataUser, loading, logIn, errorMessage }}>
            {children}
        </AuthContext.Provider>
    )
}

export { AuthProvider }

export default AuthContext
